@media screen and (min-width: 480px) {
    body {
        background-color: lightgreen;
    }
}

#main {
    border: 1px/**
 * Paste or drop some CSS here and explore
 * the syntax tree created by chosen parser.
 * Enjoy!
 */ solid black;
}

ul li {
	padding: 5px;
}

h1, h2 {
				color: red;
		}

		h2, h1 {
				font-weight: 400;
		}

@keyframes fadeOut {
				0% {
						opacity: 1;
				}
				100% {
						opacity: 0;
				}
		}

		@keyframes fadeOut {
				0% {
						opacity: 1;
				}
				100% {
						opacity: 0;
				}
		}

		.fadeOut {
				animation-name: fadeOut;
		}

h1 {
				padding: 10px 20px 30px 40px;
		}

		h2 {
				padding: 10px 20px 30px;
		}

		h3 {
				padding: 10px 20px;
		}

		h4 {
				padding: 10px;
		}

.two-gradients {
				background: linear-gradient(#fff, #999) no-repeat border-box, linear-gradient(#eee, #777) no-repeat border-box;
				background-size: 98px 50px, 18px 50px;
				background-position: 0 0, 98px 0;
				background-origin: padding-box, padding-box;
		}

h1 {
				border-width: 1px 1px 1px 1px;
				border-color: red #f00 red #f00;
				border-style: solid solid solid solid;
		}

p + p {
				font-style: italic;
		}

		h1 ~ p {
				font-size: 2em;
		}

		p > a {
				font-weight: 700;
		}

@font-face {
				font-family: Glyphicons Halflings;
				src: url(../fonts/bootstrap/glyphicons-halflings-regular.eot);
				src: url(../fonts/bootstrap/glyphicons-halflings-regular.eot?#iefix) format("embedded-opentype"),
						 url(../fonts/bootstrap/glyphicons-halflings-regular.woff2) format("woff2"),
						 url(../fonts/bootstrap/glyphicons-halflings-regular.woff) format("woff"),
						 url(../fonts/bootstrap/glyphicons-halflings-regular.ttf) format("truetype"),
						 url(../fonts/bootstrap/glyphicons-halflings-regular.svg#glyphicons_halflingsregular) format("svg")
		}

		.icon {
				font-family: Glyphicons Halflings;
		}

h1 {
				/* No expected optimisation */
				margin: 10px 20px 30px 40px;
		}

		h2 {
				/* Expected to transform to 3 values */
				margin: 10px 20px 30px 20px;
		}

		h3 {
				/* Expected to transform to 2 values */
				margin: 10px 20px 10px 20px;
		}

		h4 {
				/* Expected to transform to 1 value */
				margin: 10px 10px 10px 10px;
		}

@layer a {}
@layer b {}

@layer b {
  foo {
    color: red;
  }
}

@layer a {
  bar {
    color: green;
  }
}

